const config = {
  "previewFeatures": [],
  "clientVersion": "7.6.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─────────────────────────────────────────────────────────────\n// SCHOOL\n// Changes:\n//   - Removed: pricing_tier (belongs to Subscription, not School)\n//   - Added:   setup_status, activated_at\n//   - Added:   agreements relation\n// ─────────────────────────────────────────────────────────────\nmodel School {\n  id                  String            @id @default(uuid())\n  name                String\n  address             String?\n  city                String?\n  state               String?\n  pincode             String?\n  country             String            @default(\"IN\")\n  code                String            @unique // auto-generated: DPS-DL-2025-4872\n  serial_number       Int               @unique @default(autoincrement())\n  email               String?\n  phone               String?\n  logo_url            String?\n  timezone            String            @default(\"Asia/Kolkata\")\n  school_type         SchoolType        @default(PRIVATE) // classification, never changes\n  udise_code          String?           @unique\n  affiliation_num     String?\n  affiliated_board    String?\n  contract_signed_at  DateTime?\n  contract_expires_at DateTime?\n  onboarded_by        String? // superadmin ID\n  onboarded_at        DateTime?\n  setup_status        SchoolSetupStatus @default(PENDING_SETUP) // NEW\n  activated_at        DateTime? // NEW: when first admin accepted invite\n  is_active           Boolean           @default(true)\n  created_at          DateTime          @default(now())\n  updated_at          DateTime          @updatedAt\n\n  apiKeys                ApiKey[]\n  auditLogs              AuditLog[]\n  cards                  Card[]\n  cardOrders             CardOrder[]\n  cardRenewals           CardRenewal[]\n  cardTemplate           CardTemplate?\n  dashboardNotifications DashboardNotification[]\n  invoices               Invoice[]\n  locationEvents         LocationEvent[]\n  notifications          Notification[]\n  parentEditLogs         ParentEditLog[]\n  payments               Payment[]\n  qrAssets               QrAsset[]\n  scanLogs               ScanLog[]\n  featureFlags           SchoolFeatureFlag[]\n  settings               SchoolSettings?\n  users                  SchoolUser[]\n  students               Student[]\n  subscriptions          Subscription[]\n  agreements             SchoolAgreement[] // NEW\n  tokens                 Token[]\n  tokenBatches           TokenBatch[]\n  trustedScanZones       TrustedScanZone[]\n  webhooks               Webhook[]\n\n  @@index([code])\n  @@index([is_active])\n  @@index([serial_number])\n  @@index([setup_status]) // NEW\n  @@index([school_type]) // NEW: useful for reports\n}\n\n// ─────────────────────────────────────────────────────────────\n// SCHOOL SETTINGS — no changes\n// ─────────────────────────────────────────────────────────────\nmodel SchoolSettings {\n  id                         String            @id @default(uuid())\n  school_id                  String            @unique\n  allow_location             Boolean           @default(false)\n  allow_parent_edit          Boolean           @default(true)\n  scan_notifications_enabled Boolean           @default(true)\n  notify_on_every_scan       Boolean           @default(false)\n  scan_alert_cooldown_mins   Int               @default(60)\n  token_validity_months      Int               @default(12)\n  max_tokens_per_student     Int               @default(1)\n  default_profile_visibility ProfileVisibility @default(PUBLIC)\n  renewal_reminder_days      Int[]             @default([30, 15, 7, 1])\n  auto_deactivate_on_expiry  Boolean           @default(true)\n  school_hours_start         String            @default(\"08:00\")\n  school_hours_end           String            @default(\"17:00\")\n  school_days                Int[]             @default([1, 2, 3, 4, 5])\n  created_at                 DateTime          @default(now())\n  updated_at                 DateTime          @updatedAt\n  school                     School            @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([allow_location])\n}\n\n// ─────────────────────────────────────────────────────────────\n// SCHOOL USER\n// Changes:\n//   - Added: is_primary, invited_by, invite_sent_at,\n//            invite_accepted_at, must_change_password\n//   - Removed nothing (password_hash stays — superadmin sets it directly)\n// ─────────────────────────────────────────────────────────────\nmodel SchoolUser {\n  id                     String                  @id @default(uuid())\n  school_id              String\n  email                  String                  @unique\n  password_hash          String // superadmin sets this; user changes via dashboard\n  name                   String?\n  role                   SchoolRole              @default(ADMIN)\n  is_primary             Boolean                 @default(false) // NEW: primary contact person\n  is_active              Boolean                 @default(true)\n  must_change_password   Boolean                 @default(true) // NEW: forced on first login\n  invited_by             String? // NEW: superadmin ID who created\n  invite_sent_at         DateTime? // NEW: when credentials email was sent\n  invite_accepted_at     DateTime? // NEW: when they first logged in\n  last_login_at          DateTime?\n  created_at             DateTime                @default(now())\n  updated_at             DateTime                @updatedAt\n  dashboardNotifications DashboardNotification[]\n  school                 School                  @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  sessions               Session[]\n\n  @@index([school_id])\n  @@index([is_primary]) // NEW\n}\n\n// ─────────────────────────────────────────────────────────────\n// PARENT USER — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ParentUser {\n  id                 String                  @id @default(uuid())\n  email              String?                 @unique\n  phone              String                  @unique\n  phone_index        String?                 @unique\n  password_hash      String?\n  name               String?\n  avatar_url         String?\n  preferred_language String                  @default(\"en\")\n  preferred_theme    AppTheme                @default(SYSTEM)\n  is_phone_verified  Boolean                 @default(false)\n  is_email_verified  Boolean                 @default(false)\n  status             UserStatus              @default(ACTIVE)\n  last_login_at      DateTime?\n  deleted_at         DateTime?\n  created_at         DateTime                @default(now())\n  updated_at         DateTime                @updatedAt\n  deviceLoginLogs    DeviceLoginLog[]\n  notifications      Notification[]\n  devices            ParentDevice[]\n  editLogs           ParentEditLog[]\n  notificationPrefs  ParentNotificationPref?\n  children           ParentStudent[]\n  sessions           Session[]\n\n  @@index([phone_index])\n}\n\n// ─────────────────────────────────────────────────────────────\n// PARENT DEVICE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ParentDevice {\n  id              String              @id @default(uuid())\n  parent_id       String\n  platform        DevicePlatform\n  device_name     String?\n  device_model    String?\n  os_version      String?\n  app_version     String?\n  is_active       Boolean             @default(true)\n  last_seen_at    DateTime?\n  logged_out_at   DateTime?\n  logout_reason   DeviceLogoutReason?\n  created_at      DateTime            @default(now())\n  expo_push_token String?             @unique\n  parent          ParentUser          @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n\n  @@index([parent_id, is_active])\n}\n\n// ─────────────────────────────────────────────────────────────\n// PARENT NOTIFICATION PREF — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ParentNotificationPref {\n  id                        String     @id @default(uuid())\n  parent_id                 String     @unique\n  scan_notify_enabled       Boolean    @default(true)\n  scan_notify_push          Boolean    @default(true)\n  scan_notify_sms           Boolean    @default(false)\n  scan_notify_email         Boolean    @default(false)\n  anomaly_notify_enabled    Boolean    @default(true)\n  anomaly_notify_push       Boolean    @default(true)\n  anomaly_notify_sms        Boolean    @default(true)\n  anomaly_notify_email      Boolean    @default(true)\n  card_expiry_notify        Boolean    @default(true)\n  card_blocked_notify       Boolean    @default(true)\n  device_login_notify_email Boolean    @default(true)\n  account_change_notify     Boolean    @default(true)\n  quiet_hours_enabled       Boolean    @default(false)\n  quiet_hours_start         String?\n  quiet_hours_end           String?\n  created_at                DateTime   @default(now())\n  updated_at                DateTime   @updatedAt\n  parent                    ParentUser @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n}\n\n// ─────────────────────────────────────────────────────────────\n// SUPER ADMIN — no changes\n// ─────────────────────────────────────────────────────────────\nmodel SuperAdmin {\n  id                     String                  @id @default(uuid())\n  name                   String\n  email                  String                  @unique\n  password_hash          String\n  is_active              Boolean                 @default(true)\n  last_login_at          DateTime?\n  created_at             DateTime                @default(now())\n  updated_at             DateTime                @updatedAt\n  dashboardNotifications DashboardNotification[]\n  sessions               Session[]\n\n  @@index([email])\n}\n\n// ─────────────────────────────────────────────────────────────\n// OTP AUDIT LOG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel OtpAuditLog {\n  id           String     @id @default(uuid())\n  purpose      OtpPurpose\n  attempts     Int        @default(0)\n  max_attempts Int        @default(5)\n  verified     Boolean    @default(false)\n  verified_at  DateTime?\n  expires_at   DateTime\n  invalidated  Boolean    @default(false)\n  msg91_req_id String?\n  ip_address   String?\n  created_at   DateTime   @default(now())\n  phone_index  String\n\n  @@index([phone_index, purpose])\n  @@index([expires_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// STUDENT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel Student {\n  id                    String            @id @default(uuid())\n  school_id             String?\n  profile_type          ProfileType       @default(STUDENT)\n  setup_stage           SetupStage        @default(PENDING)\n  first_name            String?\n  last_name             String?\n  photo_url             String?\n  gender                Gender?\n  dob_encrypted         String?\n  class                 String?\n  section               String?\n  roll_number           String?\n  admission_number      String?\n  is_active             Boolean           @default(true)\n  created_at            DateTime          @default(now())\n  updated_at            DateTime          @updatedAt\n  deleted_at            DateTime?\n  card_design_url       String?\n  card_number           String?           @unique\n  design_completed_at   DateTime?\n  design_started_at     DateTime?\n  design_status         DesignStatus?     @default(PENDING)\n  pipeline_completed_at DateTime?\n  pipeline_started_at   DateTime?\n  pipeline_status       PipelineStatus?   @default(PENDING)\n  qr_code_url           String?\n  scan_url              String?\n  token                 String?           @unique\n  token_hash            String?           @unique\n  cards                 Card[]\n  orderItems            CardOrderItem[]\n  cardRenewals          CardRenewal[]\n  cardVisibility        CardVisibility?\n  emergency             EmergencyProfile?\n  locationConsent       LocationConsent?\n  locationEvents        LocationEvent[]\n  notifications         Notification[]\n  editLogs              ParentEditLog[]\n  parents               ParentStudent[]\n  scanLogs              ScanLog[]\n  school                School?           @relation(fields: [school_id], references: [id])\n  tokens                Token[]\n\n  @@index([school_id])\n  @@index([setup_stage])\n  @@index([pipeline_status])\n  @@index([card_number])\n  @@index([token_hash])\n}\n\n// ─────────────────────────────────────────────────────────────\n// PARENT STUDENT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ParentStudent {\n  id           String     @id @default(uuid())\n  parent_id    String\n  student_id   String\n  relationship String?\n  is_primary   Boolean    @default(false)\n  created_at   DateTime   @default(now())\n  parent       ParentUser @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n  student      Student    @relation(fields: [student_id], references: [id], onDelete: Cascade)\n\n  @@unique([parent_id, student_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// EMERGENCY PROFILE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel EmergencyProfile {\n  id                     String             @id @default(uuid())\n  student_id             String             @unique\n  blood_group            BloodGroup?\n  allergies              String?\n  conditions             String?\n  medications            String?\n  doctor_name            String?\n  doctor_phone_encrypted String?\n  notes                  String?\n  visibility             ProfileVisibility  @default(PUBLIC)\n  is_visible             Boolean            @default(true)\n  created_at             DateTime           @default(now())\n  updated_at             DateTime           @updatedAt\n  contacts               EmergencyContact[]\n  student                Student            @relation(fields: [student_id], references: [id], onDelete: Cascade)\n}\n\n// ─────────────────────────────────────────────────────────────\n// EMERGENCY CONTACT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel EmergencyContact {\n  id               String           @id @default(uuid())\n  profile_id       String\n  name             String\n  phone_encrypted  String\n  relationship     String?\n  priority         Int\n  display_order    Int              @default(0)\n  is_active        Boolean          @default(true)\n  call_enabled     Boolean          @default(true)\n  whatsapp_enabled Boolean          @default(true)\n  created_at       DateTime         @default(now())\n  updated_at       DateTime         @updatedAt\n  profile          EmergencyProfile @relation(fields: [profile_id], references: [id], onDelete: Cascade)\n\n  @@unique([profile_id, priority])\n  @@index([profile_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// CARD VISIBILITY — no changes\n// ─────────────────────────────────────────────────────────────\nmodel CardVisibility {\n  id                String            @id @default(uuid())\n  student_id        String            @unique\n  visibility        ProfileVisibility @default(PUBLIC)\n  hidden_fields     String[]          @default([])\n  updated_by_parent Boolean           @default(false)\n  created_at        DateTime          @default(now())\n  updated_at        DateTime          @updatedAt\n  student           Student           @relation(fields: [student_id], references: [id], onDelete: Cascade)\n}\n\n// ─────────────────────────────────────────────────────────────\n// PARENT EDIT LOG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ParentEditLog {\n  id          String         @id @default(uuid())\n  school_id   String?\n  student_id  String\n  parent_id   String\n  field_group ParentEditType\n  old_value   Json?\n  new_value   Json\n  ip_address  String?\n  user_agent  String?\n  created_at  DateTime       @default(now())\n  parent      ParentUser     @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n  school      School?        @relation(fields: [school_id], references: [id])\n  student     Student        @relation(fields: [student_id], references: [id], onDelete: Cascade)\n\n  @@index([student_id])\n  @@index([parent_id])\n  @@index([created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// TOKEN — no changes\n// ─────────────────────────────────────────────────────────────\nmodel Token {\n  id             String              @id @default(uuid())\n  school_id      String\n  student_id     String?\n  token_hash     String              @unique\n  status         TokenStatus         @default(UNASSIGNED)\n  batch_id       String?\n  order_id       String?\n  order_item_id  String?             @unique\n  replaced_by_id String?\n  activated_at   DateTime?\n  assigned_at    DateTime?\n  expires_at     DateTime?\n  revoked_at     DateTime?\n  created_at     DateTime            @default(now())\n  is_honeypot    Boolean             @default(false)\n  cards          Card[]\n  locations      LocationEvent[]\n  qrAsset        QrAsset?\n  nonces         RegistrationNonce[]\n  anomalies      ScanAnomaly[]\n  scans          ScanLog[]\n  batch          TokenBatch?         @relation(fields: [batch_id], references: [id])\n  order          CardOrder?          @relation(fields: [order_id], references: [id])\n  orderItem      CardOrderItem?      @relation(fields: [order_item_id], references: [id])\n  replacedBy     Token?              @relation(\"TokenReplacement\", fields: [replaced_by_id], references: [id])\n  replacements   Token[]             @relation(\"TokenReplacement\")\n  school         School              @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student        Student?            @relation(fields: [student_id], references: [id])\n\n  @@index([is_honeypot])\n  @@index([school_id, status])\n  @@index([order_id])\n  @@index([token_hash])\n  @@index([student_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// TOKEN BATCH — no changes\n// ─────────────────────────────────────────────────────────────\nmodel TokenBatch {\n  id              String           @id @default(uuid())\n  school_id       String\n  order_id        String?\n  count           Int\n  generated_count Int              @default(0)\n  failed_count    Int              @default(0)\n  status          TokenBatchStatus @default(PENDING)\n  created_by      String\n  notes           String?\n  completed_at    DateTime?\n  error_log       Json?\n  created_at      DateTime         @default(now())\n  updated_at      DateTime         @updatedAt\n  tokens          Token[]\n  order           CardOrder?       @relation(fields: [order_id], references: [id])\n  school          School           @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([order_id])\n  @@index([status])\n}\n\n// ─────────────────────────────────────────────────────────────\n// QR ASSET — no changes\n// ─────────────────────────────────────────────────────────────\nmodel QrAsset {\n  id           String     @id @default(uuid())\n  token_id     String     @unique\n  school_id    String\n  storage_key  String     @unique\n  public_url   String\n  format       QrFormat   @default(PNG)\n  width_px     Int        @default(512)\n  height_px    Int        @default(512)\n  file_size_kb Int?\n  qr_type      QrType\n  generated_by String\n  order_id     String?\n  is_active    Boolean    @default(true)\n  generated_at DateTime   @default(now())\n  order        CardOrder? @relation(fields: [order_id], references: [id])\n  school       School     @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  token        Token      @relation(fields: [token_id], references: [id], onDelete: Cascade)\n\n  @@index([school_id])\n  @@index([order_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// CARD ORDER — no changes\n// ─────────────────────────────────────────────────────────────\nmodel CardOrder {\n  id                       String                  @id @default(uuid())\n  school_id                String\n  subscription_id          String?\n  order_number             String                  @unique\n  order_type               OrderType\n  status                   OrderStatus             @default(PENDING)\n  payment_status           OrderPaymentStatus      @default(UNPAID)\n  advance_amount           Int?\n  advance_paid_at          DateTime?\n  balance_amount           Int?\n  balance_paid_at          DateTime?\n  delivery_name            String?\n  delivery_phone           String?\n  delivery_address         String?\n  delivery_city            String?\n  delivery_state           String?\n  delivery_pincode         String?\n  caller_name              String?\n  caller_phone             String?\n  call_notes               String?\n  notes                    String?\n  admin_notes              String?\n  confirmed_by             String?\n  confirmed_at             DateTime?\n  tokens_generated_by      String?\n  tokens_generated_at      DateTime?\n  card_design_files        Json?\n  card_design_by           String?\n  card_design_at           DateTime?\n  vendor_id                String?\n  vendor_notes             String?\n  files_sent_to_vendor_at  DateTime?\n  files_sent_by            String?\n  print_complete_at        DateTime?\n  print_complete_noted_by  String?\n  status_changed_by        String?\n  status_changed_at        DateTime?\n  status_note              String?\n  created_at               DateTime                @default(now())\n  updated_at               DateTime                @updatedAt\n  grand_total              Int?\n  unit_price               Int?\n  order_channel            OrderChannel?\n  design_completed_count   Int                     @default(0)\n  design_started_at        DateTime?\n  final_invoice_id         String?                 @unique\n  partial_invoice_id       String?                 @unique\n  pipeline_completed_count Int                     @default(0)\n  pipeline_started_at      DateTime?\n  student_count            Int\n  cards                    Card[]\n  finalInvoice             Invoice?                @relation(\"FinalInvoiceForOrder\", fields: [final_invoice_id], references: [id])\n  partialInvoice           Invoice?                @relation(\"PartialInvoiceForOrder\", fields: [partial_invoice_id], references: [id])\n  school                   School                  @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  subscription             Subscription?           @relation(fields: [subscription_id], references: [id])\n  vendor                   VendorProfile?          @relation(fields: [vendor_id], references: [id])\n  items                    CardOrderItem[]\n  dashboardNotifications   DashboardNotification[]\n  invoices                 Invoice[]\n  pipeline                 OrderPipeline?\n  shipment                 OrderShipment?\n  statusLogs               OrderStatusLog[]\n  payments                 Payment[]\n  qrAssets                 QrAsset[]\n  tokens                   Token[]\n  tokenBatches             TokenBatch[]\n\n  @@index([school_id])\n  @@index([status])\n  @@index([payment_status])\n  @@index([created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// CARD ORDER ITEM — no changes\n// ─────────────────────────────────────────────────────────────\nmodel CardOrderItem {\n  id              String          @id @default(uuid())\n  order_id        String\n  student_id      String?\n  token_id        String?         @unique\n  student_name    String\n  class           String?\n  section         String?\n  roll_number     String?\n  photo_url       String?\n  status          OrderItemStatus @default(PENDING)\n  card_design_url String?\n  card_printed    Boolean         @default(false)\n  has_issue       Boolean         @default(false)\n  issue_note      String?\n  created_at      DateTime        @default(now())\n  updated_at      DateTime        @updatedAt\n  pipeline_status PipelineStatus  @default(PENDING)\n  order           CardOrder       @relation(fields: [order_id], references: [id], onDelete: Cascade)\n  student         Student?        @relation(fields: [student_id], references: [id])\n  token           Token?\n\n  @@index([order_id])\n  @@index([student_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// ORDER STATUS LOG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel OrderStatusLog {\n  id          String       @id @default(uuid())\n  order_id    String\n  from_status OrderStatus?\n  to_status   OrderStatus\n  changed_by  String\n  note        String?\n  metadata    Json?\n  created_at  DateTime     @default(now())\n  actor_type  ActorType    @default(SYSTEM)\n  order       CardOrder    @relation(fields: [order_id], references: [id], onDelete: Cascade)\n\n  @@index([order_id, created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// ORDER SHIPMENT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel OrderShipment {\n  id                     String            @id @default(uuid())\n  order_id               String            @unique\n  shiprocket_order_id    String?\n  shiprocket_shipment_id String?\n  awb_code               String?           @unique\n  courier_name           String?\n  courier_id             Int?\n  tracking_url           String?\n  label_url              String?\n  manifest_url           String?\n  pickup_vendor_id       String?\n  pickup_name            String?\n  pickup_contact         String?\n  pickup_address         String?\n  pickup_city            String?\n  pickup_state           String?\n  pickup_pincode         String?\n  delivery_name          String?\n  delivery_phone         String?\n  delivery_address       String?\n  delivery_city          String?\n  delivery_state         String?\n  delivery_pincode       String?\n  status                 ShipmentStatus    @default(PENDING)\n  shiprocket_status      ShiprocketStatus?\n  created_by             String?\n  tracking_shared_at     DateTime?\n  tracking_shared_by     String?\n  pickup_scheduled_at    DateTime?\n  picked_up_at           DateTime?\n  estimated_delivery_at  DateTime?\n  delivered_at           DateTime?\n  delivery_confirmed_by  String?\n  notes                  String?\n  created_at             DateTime          @default(now())\n  updated_at             DateTime          @updatedAt\n  order                  CardOrder         @relation(fields: [order_id], references: [id], onDelete: Cascade)\n\n  @@index([status])\n  @@index([awb_code])\n}\n\n// ─────────────────────────────────────────────────────────────\n// VENDOR PROFILE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel VendorProfile {\n  id                  String       @id @default(uuid())\n  name                String\n  contact_name        String?\n  phone               String?\n  email               String?\n  status              VendorStatus @default(ACTIVE)\n  address             String?\n  city                String?\n  state               String?\n  pincode             String?\n  gstin               String?\n  speciality          String?\n  avg_turnaround_days Int?\n  notes               String?\n  created_at          DateTime     @default(now())\n  updated_at          DateTime     @updatedAt\n  orders              CardOrder[]\n\n  @@index([status])\n}\n\n// ─────────────────────────────────────────────────────────────\n// CARD — no changes\n// ─────────────────────────────────────────────────────────────\nmodel Card {\n  id           String        @id @default(uuid())\n  school_id    String\n  student_id   String?\n  token_id     String?\n  order_id     String?\n  card_number  String        @unique\n  file_url     String?\n  print_status PrintStatus   @default(PENDING)\n  printed_at   DateTime?\n  created_at   DateTime      @default(now())\n  order        CardOrder?    @relation(fields: [order_id], references: [id])\n  school       School        @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student      Student?      @relation(fields: [student_id], references: [id], onDelete: Cascade)\n  token        Token?        @relation(fields: [token_id], references: [id])\n  renewals     CardRenewal[]\n\n  @@index([school_id])\n  @@index([token_id])\n  @@index([order_id])\n  @@index([card_number])\n}\n\n// ─────────────────────────────────────────────────────────────\n// CARD RENEWAL\n// Changes:\n//   - Added:   subscription_id, unit_price_snapshot, invoice_id\n//   - Removed: pricing_tier, school_type (redundant — derive from subscription)\n// ─────────────────────────────────────────────────────────────\nmodel CardRenewal {\n  id                  String        @id @default(uuid())\n  card_id             String\n  student_id          String\n  school_id           String\n  subscription_id     String? // NEW: which subscription period\n  renewed_by          String?\n  renewer_type        ActorType     @default(SYSTEM) // changed default to SYSTEM (auto-renewal)\n  old_expiry          DateTime\n  new_expiry          DateTime\n  unit_price_snapshot Int // NEW: price locked at renewal time (paise)\n  amount_paid         Int // before tax\n  tax_amount          Int           @default(0)\n  total_paid          Int           @default(0) // NEW: amount_paid + tax_amount\n  invoice_id          String? // NEW: which invoice triggered this renewal\n  payment_id          String?\n  created_at          DateTime      @default(now())\n  card                Card          @relation(fields: [card_id], references: [id], onDelete: Cascade)\n  invoice             Invoice?      @relation(fields: [invoice_id], references: [id]) // NEW\n  payment             Payment?      @relation(\"RenewalPayment\", fields: [payment_id], references: [id])\n  school              School        @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student             Student       @relation(fields: [student_id], references: [id], onDelete: Cascade)\n  subscription        Subscription? @relation(fields: [subscription_id], references: [id]) // NEW\n\n  @@index([card_id])\n  @@index([student_id])\n  @@index([subscription_id]) // NEW\n  @@index([invoice_id]) // NEW\n}\n\n// ─────────────────────────────────────────────────────────────\n// NEW: PRICING CONFIG\n// Single source of truth for all plan prices.\n// Only SuperAdmin manages this. Never read at runtime — only at\n// subscription creation. All runtime pricing uses snapshots.\n// ─────────────────────────────────────────────────────────────\nmodel PricingConfig {\n  id              String   @id @default(uuid())\n  plan            PlanType @unique\n  label           String // \"Basic Plan\", \"Premium Plan\"\n  unit_price      Int // per card per year (paise)\n  renewal_price   Int // renewal per card per year (paise)\n  advance_percent Int      @default(50) // % charged upfront on order\n  is_active       Boolean  @default(true)\n  effective_from  DateTime @default(now())\n  notes           String?\n  created_by      String? // superadmin ID\n  created_at      DateTime @default(now())\n  updated_at      DateTime @updatedAt\n\n  @@index([plan])\n  @@index([is_active])\n}\n\n// ─────────────────────────────────────────────────────────────\n// SUBSCRIPTION\n// Changes:\n//   - Removed: pricing_tier, unit_price (raw with hardcoded default)\n//   - Added:   unit_price_snapshot, renewal_price_snapshot,\n//              advance_percent, is_custom_pricing, custom_price_note,\n//              custom_approved_by, custom_approved_at,\n//              is_pilot, pilot_expires_at, pilot_converted_at,\n//              active_card_count, total_invoiced, total_received,\n//              balance_due, renewals relation\n//   - Fixed:   plan default was GOVT_STANDARD — now no default,\n//              must be explicitly set at creation\n// ─────────────────────────────────────────────────────────────\nmodel Subscription {\n  id        String @id @default(uuid())\n  school_id String\n\n  // Plan — locked at registration, only SuperAdmin can change via reprice\n  plan   PlanType\n  status SubscriptionStatus @default(TRIALING)\n\n  // Price snapshot — copied once at creation, NEVER changes after\n  // For CUSTOM: set manually by SuperAdmin\n  // For BASIC/PREMIUM: copied from PricingConfig\n  unit_price_snapshot    Int // paise\n  renewal_price_snapshot Int // paise\n  advance_percent        Int @default(50) // % charged upfront\n\n  // Custom pricing fields (only populated when plan = CUSTOM)\n  is_custom_pricing  Boolean   @default(false)\n  custom_price_note  String? // \"Bulk deal, 800 students\"\n  custom_approved_by String? // superadmin ID\n  custom_approved_at DateTime?\n\n  // Pilot flag — replaces FREE_PILOT plan entirely\n  is_pilot           Boolean   @default(false)\n  pilot_expires_at   DateTime?\n  pilot_converted_at DateTime? // when pilot → paid\n\n  // Billing totals — auto maintained by updateSubscriptionTotals()\n  student_count     Int @default(0) // confirmed on first order\n  active_card_count Int @default(0) // used for renewal calculation\n  grand_total       Int @default(0) // unit_price_snapshot × student_count\n  total_invoiced    Int @default(0) // sum of all non-cancelled invoices\n  total_received    Int @default(0) // sum of SUCCESS payments\n  balance_due       Int @default(0) // total_invoiced - total_received\n\n  // Period\n  current_period_start DateTime\n  current_period_end   DateTime\n  trial_ends_at        DateTime?\n  fully_paid_at        DateTime?\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  school     School            @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  cardOrders CardOrder[]\n  invoices   Invoice[]\n  renewals   CardRenewal[] // NEW\n  agreements SchoolAgreement[] // NEW\n  payments   Payment[] // NEW\n\n  @@index([school_id])\n  @@index([status])\n  @@index([current_period_end]) // NEW: for renewal cron queries\n  @@index([is_pilot]) // NEW: for pilot tracking\n}\n\n// ─────────────────────────────────────────────────────────────\n// INVOICE\n// Changes:\n//   - Removed: category, order_invoice_type, renewal_invoice_type\n//              (collapsed into single invoice_type field)\n//   - Added:   invoice_type, card_count, tax_percent,\n//              subscription_id made required not nullable\n//   - Fixed:   subscription_id was nullable with no relation properly\n//              defined — now properly typed\n// ─────────────────────────────────────────────────────────────\nmodel Invoice {\n  id              String  @id @default(uuid())\n  school_id       String\n  subscription_id String // required — every invoice belongs to a subscription\n  order_id        String? // only for ORDER_ADVANCE and ORDER_FINAL types\n  invoice_number  String  @unique\n\n  // Single clean type — replaces category + order_invoice_type + renewal_invoice_type\n  invoice_type InvoiceType\n\n  // Calculation snapshot — all auto-filled by service, never manual\n  student_count Int @default(0) // for order invoices\n  card_count    Int @default(0) // for renewal invoices\n  unit_price    Int // snapshot at invoice time (paise)\n  amount        Int // before tax (paise)\n  tax_percent   Int @default(18) // GST %\n  tax_amount    Int // auto = amount × tax_percent / 100\n  total_amount  Int // amount + tax_amount\n\n  status           InvoiceStatus @default(ISSUED)\n  issued_at        DateTime      @default(now())\n  due_at           DateTime?\n  paid_at          DateTime?\n  pdf_url          String?\n  pdf_generated_at DateTime?\n  notes            String?\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  // Back-relations for CardOrder partial/final invoice shortcuts (kept for compatibility)\n  finalOrder   CardOrder? @relation(\"FinalInvoiceForOrder\")\n  partialOrder CardOrder? @relation(\"PartialInvoiceForOrder\")\n\n  order        CardOrder?    @relation(fields: [order_id], references: [id], onDelete: Cascade)\n  school       School        @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  subscription Subscription  @relation(fields: [subscription_id], references: [id])\n  payments     Payment[]\n  renewals     CardRenewal[] // NEW: renewals triggered by this invoice\n\n  @@index([school_id])\n  @@index([subscription_id]) // NEW\n  @@index([order_id])\n  @@index([invoice_type]) // replaces @@index([category, order_invoice_type])\n  @@index([status])\n  @@index([invoice_number])\n  @@index([due_at]) // NEW: for overdue queries\n}\n\n// ─────────────────────────────────────────────────────────────\n// PAYMENT\n// Changes:\n//   - Fixed:   order_id was required (String) — now optional (String?)\n//              because renewal payments have no order\n//   - Added:   subscription_id relation properly, recorded_by,\n//              notes, updated_at\n//   - Removed: is_advance (invoice_type already tells us this)\n//   - Fixed:   invoice_id was nullable — kept nullable for legacy\n//              but all new payments must have invoice_id\n// ─────────────────────────────────────────────────────────────\nmodel Payment {\n  id              String  @id @default(uuid())\n  school_id       String\n  invoice_id      String // required — payment always against an invoice\n  order_id        String? // optional reference only (go through invoice)\n  subscription_id String? // for direct subscription payments\n\n  amount       Int // paise — actual amount received\n  payment_ref  String?       @unique // bank ref / UPI ID — duplicate detection\n  status       PaymentStatus @default(PENDING)\n  payment_mode PaymentMode   @default(BANK_TRANSFER)\n  recorded_by  String // superadmin ID — all payments are manual\n  notes        String? // any context about this payment\n  metadata     Json? // extra data if needed\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  renewals     CardRenewal[] @relation(\"RenewalPayment\")\n  invoice      Invoice       @relation(fields: [invoice_id], references: [id])\n  order        CardOrder?    @relation(fields: [order_id], references: [id])\n  school       School        @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  subscription Subscription? @relation(fields: [subscription_id], references: [id])\n\n  @@index([school_id])\n  @@index([invoice_id])\n  @@index([order_id])\n  @@index([subscription_id]) // NEW\n  @@index([status]) // NEW\n  @@index([created_at])\n  @@index([payment_ref])\n}\n\n// ─────────────────────────────────────────────────────────────\n// NEW: SCHOOL AGREEMENT\n// Legal consent trail. Created at school registration and on\n// every plan change / reprice. Immutable once created.\n// ─────────────────────────────────────────────────────────────\nmodel SchoolAgreement {\n  id              String           @id @default(uuid())\n  school_id       String\n  subscription_id String\n  agreed_at       DateTime         @default(now())\n  agreed_by       String // superadmin ID\n  agreed_via      AgreementChannel\n  document_url    String? // signed agreement PDF in R2\n  ip_address      String?\n  notes           String?\n  is_active       Boolean          @default(true)\n  created_at      DateTime         @default(now())\n\n  school       School       @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  subscription Subscription @relation(fields: [subscription_id], references: [id])\n\n  @@index([school_id])\n  @@index([subscription_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// DASHBOARD NOTIFICATION — no changes\n// ─────────────────────────────────────────────────────────────\nmodel DashboardNotification {\n  id             String                    @id @default(uuid())\n  user_id        String\n  user_type      DashboardUserType\n  type           DashboardNotificationType\n  title          String\n  body           String\n  metadata       Json?\n  read           Boolean                   @default(false)\n  read_at        DateTime?\n  created_at     DateTime                  @default(now())\n  school_id      String?\n  order_id       String?\n  school_user_id String?\n  super_admin_id String?\n  order          CardOrder?                @relation(fields: [order_id], references: [id])\n  school         School?                   @relation(fields: [school_id], references: [id])\n  schoolUser     SchoolUser?               @relation(fields: [school_user_id], references: [id], onDelete: Cascade)\n  superAdmin     SuperAdmin?               @relation(fields: [super_admin_id], references: [id], onDelete: Cascade)\n\n  @@index([user_id, user_type])\n  @@index([user_id, read])\n  @@index([user_id, created_at])\n  @@index([type, created_at])\n  @@index([school_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// SCAN LOG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ScanLog {\n  id                   String         @id @default(uuid())\n  token_id             String\n  school_id            String\n  result               ScanResult\n  ip_address           String?\n  ip_city              String?\n  ip_country           String?\n  ip_region            String?\n  ip_capture_basis     IpCaptureBasis @default(LEGITIMATE_INTEREST)\n  location_derived     Boolean        @default(true)\n  latitude             Float?\n  longitude            Float?\n  device_hash          String?\n  user_agent           String?\n  response_time_ms     Int?\n  created_at           DateTime       @default(now())\n  device_info          Json?\n  dispatched_at        DateTime?\n  dispatched_channels  String[]       @default([])\n  emergency_dispatched Boolean        @default(false)\n  failed_channels      String[]       @default([])\n  scan_type            ScanType       @default(OTHER)\n  scanned_at           DateTime       @default(now())\n  scanned_by           String?\n  student_id           String?\n  scan_purpose         ScanPurpose    @default(QR_SCAN)\n  school               School         @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student              Student?       @relation(fields: [student_id], references: [id])\n  token                Token          @relation(fields: [token_id], references: [id], onDelete: Cascade)\n\n  @@index([token_id, created_at])\n  @@index([student_id, created_at])\n  @@index([school_id, created_at])\n  @@index([school_id, result])\n  @@index([scan_type, created_at])\n  @@index([emergency_dispatched, dispatched_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// SCAN ANOMALY — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ScanAnomaly {\n  id           String          @id @default(uuid())\n  token_id     String\n  anomaly_type AnomalyType\n  severity     AnomalySeverity @default(MEDIUM)\n  reason       String?\n  metadata     Json?\n  resolved     Boolean         @default(false)\n  resolved_at  DateTime?\n  resolved_by  String?\n  created_at   DateTime        @default(now())\n  token        Token           @relation(fields: [token_id], references: [id], onDelete: Cascade)\n\n  @@index([token_id])\n  @@index([anomaly_type])\n}\n\n// ─────────────────────────────────────────────────────────────\n// SCAN RATE LIMIT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ScanRateLimit {\n  id              String                  @id @default(uuid())\n  identifier      String\n  identifier_type RateLimitIdentifierType\n  count           Int                     @default(1)\n  window_start    DateTime                @default(now())\n  last_hit        DateTime                @default(now())\n  blocked_until   DateTime?\n  blocked_reason  String?\n  block_count     Int                     @default(0)\n\n  @@unique([identifier, identifier_type])\n  @@index([blocked_until])\n}\n\n// ─────────────────────────────────────────────────────────────\n// LOCATION CONSENT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel LocationConsent {\n  id           String   @id @default(uuid())\n  student_id   String   @unique\n  enabled      Boolean  @default(false)\n  consented_by String?\n  consent_text String?\n  ip_address   String?\n  created_at   DateTime @default(now())\n  updated_at   DateTime @updatedAt\n  student      Student  @relation(fields: [student_id], references: [id], onDelete: Cascade)\n}\n\n// ─────────────────────────────────────────────────────────────\n// LOCATION EVENT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel LocationEvent {\n  id         String         @id @default(uuid())\n  student_id String\n  school_id  String\n  token_id   String?\n  latitude   Float\n  longitude  Float\n  accuracy   Float?\n  altitude   Float?\n  source     LocationSource @default(SCAN_TRIGGER)\n  created_at DateTime       @default(now())\n  school     School         @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student    Student        @relation(fields: [student_id], references: [id], onDelete: Cascade)\n  token      Token?         @relation(fields: [token_id], references: [id])\n\n  @@index([student_id, created_at])\n  @@index([school_id, created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// REGISTRATION NONCE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel RegistrationNonce {\n  id          String    @id @default(uuid())\n  nonce       String    @unique\n  token_id    String\n  phone_index String?\n  expires_at  DateTime\n  used        Boolean   @default(false)\n  used_at     DateTime?\n  created_at  DateTime  @default(now())\n  token       Token     @relation(fields: [token_id], references: [id], onDelete: Cascade)\n\n  @@index([token_id])\n  @@index([expires_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// TRUSTED SCAN ZONE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel TrustedScanZone {\n  id         String   @id @default(uuid())\n  school_id  String\n  label      String\n  ip_range   String?\n  latitude   Float?\n  longitude  Float?\n  radius_m   Int      @default(200)\n  is_active  Boolean  @default(true)\n  created_by String?\n  updated_by String?\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n  school     School   @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([school_id, is_active])\n}\n\n// ─────────────────────────────────────────────────────────────\n// NOTIFICATION — no changes\n// ─────────────────────────────────────────────────────────────\nmodel Notification {\n  id           String              @id @default(uuid())\n  school_id    String\n  student_id   String?\n  parent_id    String?\n  channel      NotificationChannel\n  status       NotificationStatus  @default(QUEUED)\n  payload      Json?\n  retry_count  Int                 @default(0)\n  sent_at      DateTime?\n  error        String?\n  created_at   DateTime            @default(now())\n  content      String?\n  recipient    String\n  subject      String?\n  type         String\n  order_id     String?\n  event_type   String?\n  latency_ms   Int?\n  provider_ref String?\n  parent       ParentUser?         @relation(fields: [parent_id], references: [id])\n  school       School              @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student      Student?            @relation(fields: [student_id], references: [id])\n\n  @@index([school_id])\n  @@index([status, created_at])\n  @@index([channel, status])\n  @@index([order_id])\n  @@index([event_type, created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// AUDIT LOG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel AuditLog {\n  id         String    @id @default(uuid())\n  school_id  String?\n  actor_id   String\n  actor_type ActorType\n  action     String\n  entity     String\n  entity_id  String\n  old_value  Json?\n  new_value  Json?\n  metadata   Json?\n  ip_address String?\n  user_agent String?\n  created_at DateTime  @default(now())\n  school     School?   @relation(fields: [school_id], references: [id])\n\n  @@index([actor_id])\n  @@index([school_id])\n  @@index([entity, entity_id])\n  @@index([created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// API KEY — no changes\n// ─────────────────────────────────────────────────────────────\nmodel ApiKey {\n  id           String    @id @default(uuid())\n  school_id    String\n  name         String\n  key_hash     String    @unique\n  key_prefix   String\n  scopes       String[]\n  last_used_at DateTime?\n  expires_at   DateTime?\n  revoked_at   DateTime?\n  created_at   DateTime  @default(now())\n  school       School    @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([school_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// WEBHOOK — no changes\n// ─────────────────────────────────────────────────────────────\nmodel Webhook {\n  id          String            @id @default(uuid())\n  school_id   String\n  url         String\n  secret_hash String\n  events      String[]\n  is_active   Boolean           @default(true)\n  created_at  DateTime          @default(now())\n  school      School            @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  deliveries  WebhookDelivery[]\n\n  @@index([school_id, is_active])\n}\n\n// ─────────────────────────────────────────────────────────────\n// WEBHOOK DELIVERY — no changes\n// ─────────────────────────────────────────────────────────────\nmodel WebhookDelivery {\n  id              String    @id @default(uuid())\n  webhook_id      String\n  idempotency_key String?   @unique\n  event_type      String\n  payload         Json\n  status_code     Int?\n  response        String?\n  attempt         Int       @default(1)\n  delivered_at    DateTime?\n  created_at      DateTime  @default(now())\n  webhook         Webhook   @relation(fields: [webhook_id], references: [id], onDelete: Cascade)\n\n  @@index([webhook_id, created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// WEBHOOK EVENT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel WebhookEvent {\n  id           String    @id @default(uuid())\n  provider     String\n  event_type   String\n  payload      Json\n  received_at  DateTime  @default(now())\n  processed    Boolean   @default(false)\n  processed_at DateTime?\n  error        String?\n\n  @@index([provider, event_type])\n  @@index([processed])\n}\n\n// ─────────────────────────────────────────────────────────────\n// DEAD LETTER QUEUE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel DeadLetterQueue {\n  id            String    @id @default(uuid())\n  job_type      String\n  payload       Json\n  error_message String\n  retry_count   Int       @default(0)\n  last_attempt  DateTime  @default(now())\n  resolved      Boolean   @default(false)\n  resolved_at   DateTime?\n  created_at    DateTime  @default(now())\n\n  @@index([job_type, resolved])\n}\n\n// ─────────────────────────────────────────────────────────────\n// IDEMPOTENCY KEY — no changes\n// ─────────────────────────────────────────────────────────────\nmodel IdempotencyKey {\n  id            String   @id @default(uuid())\n  key           String   @unique\n  resource_type String\n  resource_id   String\n  status        String\n  response      Json?\n  expires_at    DateTime\n  created_at    DateTime @default(now())\n\n  @@index([expires_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// FEATURE FLAG OVERRIDE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel FeatureFlagOverride {\n  id          String    @id @default(uuid())\n  flag_key    String\n  target_type String\n  target_id   String\n  enabled     Boolean\n  percentage  Int?\n  expires_at  DateTime?\n  created_by  String\n  created_at  DateTime  @default(now())\n  updated_at  DateTime  @updatedAt\n\n  @@unique([flag_key, target_type, target_id])\n  @@index([flag_key])\n}\n\n// ─────────────────────────────────────────────────────────────\n// AUTH ATTEMPT — no changes\n// ─────────────────────────────────────────────────────────────\nmodel AuthAttempt {\n  id              String   @id @default(uuid())\n  identifier      String\n  identifier_type String\n  success         Boolean  @default(false)\n  failure_reason  String?\n  ip_address      String?\n  user_agent      String?\n  created_at      DateTime @default(now())\n\n  @@index([identifier, created_at])\n  @@index([ip_address, created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// IP BLOCKLIST — no changes\n// ─────────────────────────────────────────────────────────────\nmodel IpBlocklist {\n  id         String    @id @default(uuid())\n  ip_address String    @unique\n  reason     String\n  blocked_by String\n  blocked_at DateTime  @default(now())\n  expires_at DateTime?\n  is_active  Boolean   @default(true)\n\n  @@index([ip_address, is_active])\n  @@index([expires_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// ORDER PIPELINE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel OrderPipeline {\n  id               String               @id @default(uuid())\n  order_id         String               @unique\n  current_step     PipelineStepName\n  overall_progress Int                  @default(0)\n  is_stalled       Boolean              @default(false)\n  stalled_at       DateTime?\n  stalled_reason   String?\n  started_at       DateTime             @default(now())\n  completed_at     DateTime?\n  updated_at       DateTime             @updatedAt\n  order            CardOrder            @relation(fields: [order_id], references: [id], onDelete: Cascade)\n  steps            OrderStepExecution[]\n\n  @@index([order_id])\n  @@index([current_step])\n  @@index([is_stalled])\n}\n\n// ─────────────────────────────────────────────────────────────\n// ORDER STEP EXECUTION — no changes\n// ─────────────────────────────────────────────────────────────\nmodel OrderStepExecution {\n  id              String           @id @default(uuid())\n  pipeline_id     String\n  order_id        String\n  step            PipelineStepName\n  attempt_number  Int              @default(1)\n  status          StepStatus       @default(PENDING)\n  started_at      DateTime?\n  completed_at    DateTime?\n  duration_ms     Int?\n  progress        Int              @default(0)\n  progress_detail Json?\n  result_summary  Json?\n  error_log       Json?\n  triggered_by    String\n  triggered_at    DateTime         @default(now())\n  jobs            JobExecution[]\n  pipeline        OrderPipeline    @relation(fields: [pipeline_id], references: [id], onDelete: Cascade)\n  logs            StepLog[]\n\n  @@unique([pipeline_id, step, attempt_number])\n  @@index([pipeline_id])\n  @@index([order_id])\n  @@index([step, status])\n}\n\n// ─────────────────────────────────────────────────────────────\n// JOB EXECUTION — no changes\n// ─────────────────────────────────────────────────────────────\nmodel JobExecution {\n  id                String             @id @default(uuid())\n  step_execution_id String\n  order_id          String\n  queue_name        String\n  bullmq_job_id     String?\n  job_name          String\n  status            JobStatus          @default(QUEUED)\n  payload           Json\n  queued_at         DateTime           @default(now())\n  started_at        DateTime?\n  completed_at      DateTime?\n  duration_ms       Int?\n  progress          Int                @default(0)\n  attempt_number    Int                @default(1)\n  max_attempts      Int                @default(3)\n  last_error        String?\n  error_log         Json?\n  result            Json?\n  stepExecution     OrderStepExecution @relation(fields: [step_execution_id], references: [id], onDelete: Cascade)\n\n  @@index([step_execution_id])\n  @@index([order_id])\n  @@index([queue_name, status])\n}\n\n// ─────────────────────────────────────────────────────────────\n// STEP LOG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel StepLog {\n  id                String             @id @default(uuid())\n  step_execution_id String\n  order_id          String\n  job_execution_id  String?\n  level             String\n  message           String\n  context           Json?\n  created_at        DateTime           @default(now())\n  stepExecution     OrderStepExecution @relation(fields: [step_execution_id], references: [id], onDelete: Cascade)\n\n  @@index([step_execution_id])\n  @@index([order_id, created_at])\n  @@index([level, created_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// FEATURE FLAG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel FeatureFlag {\n  id          String   @id @default(uuid())\n  key         String   @unique\n  enabled     Boolean  @default(false)\n  description String?\n  metadata    Json?\n  updated_at  DateTime @updatedAt\n}\n\n// ─────────────────────────────────────────────────────────────\n// SCHOOL FEATURE FLAG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel SchoolFeatureFlag {\n  id         String   @id @default(uuid())\n  school_id  String\n  key        String\n  enabled    Boolean\n  updated_at DateTime @updatedAt\n  school     School   @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@unique([school_id, key])\n  @@index([school_id])\n}\n\n// ─────────────────────────────────────────────────────────────\n// CARD TEMPLATE — no changes\n// ─────────────────────────────────────────────────────────────\nmodel CardTemplate {\n  id                 String   @id @default(uuid())\n  school_id          String   @unique\n  logo_url           String?\n  background_color   String   @default(\"#FFFFFF\")\n  primary_color      String   @default(\"#000000\")\n  text_color         String   @default(\"#000000\")\n  qr_dark_color      String   @default(\"#000000\")\n  qr_light_color     String   @default(\"#FFFFFF\")\n  cover_accent_color String   @default(\"#E8342A\")\n  cover_tagline      String?\n  cards_per_sheet    Int      @default(8)\n  card_width         Int      @default(640)\n  card_height        Int      @default(400)\n  show_student_name  Boolean  @default(true)\n  show_class         Boolean  @default(true)\n  show_school_name   Boolean  @default(true)\n  show_photo         Boolean  @default(true)\n  is_locked          Boolean  @default(true)\n  updated_by         String?\n  front_template_url String?\n  back_template_url  String?\n  created_at         DateTime @default(now())\n  updated_at         DateTime @updatedAt\n  school             School   @relation(fields: [school_id], references: [id], onDelete: Cascade)\n}\n\n// ─────────────────────────────────────────────────────────────\n// SESSION — no changes\n// ─────────────────────────────────────────────────────────────\nmodel Session {\n  id                 String               @id @default(uuid())\n  parent_user_id     String?\n  school_user_id     String?\n  admin_user_id      String?\n  refresh_token_hash String               @unique\n  device_id          String?\n  device_info        String?\n  user_agent         String?\n  ip_address         String?\n  is_active          Boolean              @default(true)\n  revoked_at         DateTime?\n  revoke_reason      SessionRevokeReason?\n  last_active_at     DateTime?\n  expires_at         DateTime\n  created_at         DateTime             @default(now())\n  superAdmin         SuperAdmin?          @relation(fields: [admin_user_id], references: [id], onDelete: Cascade)\n  parentUser         ParentUser?          @relation(fields: [parent_user_id], references: [id], onDelete: Cascade)\n  schoolUser         SchoolUser?          @relation(fields: [school_user_id], references: [id], onDelete: Cascade)\n\n  @@index([parent_user_id, is_active])\n  @@index([school_user_id, is_active])\n  @@index([admin_user_id])\n  @@index([expires_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// BLACKLIST TOKEN — no changes\n// ─────────────────────────────────────────────────────────────\nmodel BlacklistToken {\n  token_hash String   @id\n  expires_at DateTime\n  created_at DateTime @default(now())\n\n  @@index([expires_at])\n}\n\n// ─────────────────────────────────────────────────────────────\n// DEVICE LOGIN LOG — no changes\n// ─────────────────────────────────────────────────────────────\nmodel DeviceLoginLog {\n  id            String         @id @default(uuid())\n  parent_id     String\n  device_name   String?\n  device_model  String?\n  platform      DevicePlatform\n  os_version    String?\n  app_version   String?\n  ip_address    String?\n  ip_city       String?\n  ip_country    String?\n  login_at      DateTime       @default(now())\n  email_sent    Boolean        @default(false)\n  email_sent_at DateTime?\n  was_forced    Boolean        @default(false)\n  parent        ParentUser     @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n\n  @@index([parent_id, login_at])\n}\n\n// ═════════════════════════════════════════════════════════════\n// ENUMS\n// ═════════════════════════════════════════════════════════════\n\nenum UserStatus {\n  ACTIVE\n  SUSPENDED\n  DELETED\n}\n\nenum AppTheme {\n  LIGHT\n  DARK\n  SYSTEM\n}\n\nenum ProfileType {\n  STUDENT\n  ELDERLY\n  PET\n  INDIVIDUAL\n}\n\nenum SetupStage {\n  PENDING\n  BASIC\n  COMPLETE\n  VERIFIED\n}\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n  PREFER_NOT_TO_SAY\n}\n\nenum BloodGroup {\n  A_POS\n  A_NEG\n  B_POS\n  B_NEG\n  AB_POS\n  AB_NEG\n  O_POS\n  O_NEG\n  UNKNOWN\n}\n\nenum TokenStatus {\n  UNASSIGNED\n  ISSUED\n  ACTIVE\n  INACTIVE\n  REVOKED\n  EXPIRED\n}\n\nenum SchoolRole {\n  ADMIN\n}\n\nenum ScanResult {\n  SUCCESS\n  INVALID\n  REVOKED\n  EXPIRED\n  INACTIVE\n  UNREGISTERED\n  ISSUED\n  RATE_LIMITED\n  ERROR\n}\n\nenum ScanPurpose {\n  QR_SCAN\n  MANUAL_LOOKUP\n  HONEYPOT\n}\n\nenum AnomalyType {\n  HIGH_FREQUENCY\n  MULTIPLE_LOCATIONS\n  SUSPICIOUS_IP\n  AFTER_HOURS\n  BULK_SCRAPING\n  HONEYPOT_TRIGGERED\n  REPEATED_FAILURE\n}\n\nenum AnomalySeverity {\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\nenum SubscriptionStatus {\n  TRIALING\n  ACTIVE\n  PAST_DUE\n  CANCELED\n  EXPIRED\n}\n\n// NEW: Clean plan types — what the school is paying for\n// FREE_PILOT removed — handled by Subscription.is_pilot flag\nenum PlanType {\n  BASIC\n  PREMIUM\n  CUSTOM\n}\n\nenum OrderPaymentStatus {\n  UNPAID\n  PARTIALLY_PAID\n  FULLY_PAID\n  REFUNDED\n}\n\nenum PaymentStatus {\n  PENDING\n  SUCCESS\n  FAILED\n  REFUNDED\n}\n\n// NEW: Single invoice type — replaces InvoiceCategory + OrderInvoiceType + RenewalInvoiceType\nenum InvoiceType {\n  ORDER_ADVANCE // 50% upfront, generated when order is CONFIRMED\n  ORDER_FINAL // remaining balance, generated after DELIVERED\n  RENEWAL // annual renewal, auto-generated 30 days before expiry\n  CUSTOM // one-off adjustments, credit notes\n}\n\nenum InvoiceStatus {\n  ISSUED\n  PAID\n  OVERDUE\n  CANCELLED\n}\n\nenum OrderType {\n  BLANK\n  PRE_DETAILS\n}\n\nenum OrderMode {\n  BULK\n  SINGLE\n}\n\nenum OrderChannel {\n  DASHBOARD\n  CALL\n}\n\nenum OrderStatus {\n  PENDING\n  CONFIRMED\n  PAYMENT_PENDING\n  ADVANCE_RECEIVED\n  TOKEN_GENERATED\n  CARD_DESIGN\n  CARD_DESIGN_REVISION\n  CARD_DESIGN_READY\n  DESIGN_APPROVED\n  SENT_TO_VENDOR\n  PRINTING\n  PRINT_COMPLETE\n  SHIPPED\n  READY_TO_SHIP\n  OUT_FOR_DELIVERY\n  DELIVERED\n  BALANCE_PENDING\n  COMPLETED\n  CANCELLED\n  REFUNDED\n}\n\nenum OrderItemStatus {\n  PENDING\n  TOKEN_GENERATED\n  CARD_DESIGNED\n  PRINTED\n  SHIPPED\n  DELIVERED\n}\n\nenum ShipmentStatus {\n  PENDING\n  PICKUP_SCHEDULED\n  PICKED_UP\n  IN_TRANSIT\n  OUT_FOR_DELIVERY\n  DELIVERED\n  FAILED\n  RETURNED\n}\n\nenum TokenBatchStatus {\n  PENDING\n  PROCESSING\n  COMPLETE\n  PARTIAL\n  FAILED\n}\n\nenum SchoolType {\n  GOVERNMENT\n  PRIVATE\n  INTERNATIONAL\n  NGO\n}\n\n// KEPT for any legacy references — but no longer used in new models\n// Can be removed in a future migration once all references are cleared\nenum PricingTier {\n  GOVT_STANDARD\n  PRIVATE_STANDARD\n  ENTERPRISE\n  FREE_PILOT\n}\n\nenum PaymentMode {\n  BANK_TRANSFER\n  UPI\n  CHEQUE\n  CASH\n}\n\nenum VendorStatus {\n  ACTIVE\n  INACTIVE\n  BLACKLISTED\n}\n\nenum ShiprocketStatus {\n  PENDING\n  PICKUP_SCHEDULED\n  PICKED_UP\n  IN_TRANSIT\n  OUT_FOR_DELIVERY\n  DELIVERED\n  UNDELIVERED\n  CANCELLED\n  RTO_INITIATED\n  RTO_DELIVERED\n}\n\nenum PrintStatus {\n  PENDING\n  PRINTED\n  REPRINTED\n  FAILED\n}\n\nenum QrFormat {\n  PNG\n  SVG\n  PDF\n}\n\nenum QrType {\n  BLANK\n  PRE_DETAILS\n}\n\nenum DashboardUserType {\n  SUPER_ADMIN\n  SCHOOL_ADMIN\n}\n\nenum DashboardNotificationType {\n  ORDER_PLACED\n  ORDER_CONFIRMED\n  TOKEN_GENERATION_COMPLETE\n  DESIGN_READY_FOR_APPROVAL\n  CARD_DESIGN_READY\n  CARDS_SHIPPED\n  CARDS_DELIVERED\n  PARTIAL_INVOICE_GENERATED\n  INVOICE_GENERATED\n  PIPELINE_STALLED\n  DLQ_NEW_ENTRY\n  EMERGENCY_FIRED\n  RENEWAL_DUE // NEW: renewal reminder\n  PAYMENT_RECEIVED // NEW: payment recorded\n  SUBSCRIPTION_ACTIVATED // NEW: first payment confirmed\n}\n\nenum NotificationChannel {\n  SMS\n  EMAIL\n  PUSH\n  WHATSAPP\n}\n\nenum NotificationStatus {\n  QUEUED\n  SENT\n  FAILED\n  SUPPRESSED\n}\n\nenum ActorType {\n  SUPER_ADMIN\n  ADMIN\n  PARENT_USER\n  SYSTEM\n}\n\nenum ProfileVisibility {\n  PUBLIC\n  MINIMAL\n  HIDDEN\n}\n\nenum LocationSource {\n  SCAN_TRIGGER\n  PARENT_APP\n  MANUAL\n}\n\nenum IpCaptureBasis {\n  LEGITIMATE_INTEREST\n  CONSENT\n  LEGAL_OBLIGATION\n}\n\nenum ParentEditType {\n  EMERGENCY_CONTACTS\n  EMERGENCY_PROFILE\n  STUDENT_NAME\n  STUDENT_PHOTO\n  PARENT_PHONE\n  PARENT_EMAIL\n  CARD_VISIBILITY\n  CARD_BLOCK\n  CARD_REPLACEMENT\n  NOTIFICATION_PREFS\n}\n\nenum OtpPurpose {\n  LOGIN\n  PHONE_VERIFY\n  CARD_BLOCK\n  CARD_REPLACEMENT\n  EMAIL_VERIFY\n  DEVICE_CHANGE\n  CHANGE_PIN\n}\n\nenum RateLimitIdentifierType {\n  IP\n  DEVICE\n  TOKEN\n}\n\nenum DevicePlatform {\n  IOS\n  ANDROID\n  WEB\n}\n\nenum DeviceLogoutReason {\n  NEW_DEVICE_LOGIN\n  MANUAL_LOGOUT\n  SESSION_EXPIRED\n  ADMIN_REVOKED\n  SUSPICIOUS_ACTIVITY\n}\n\nenum SessionRevokeReason {\n  NEW_DEVICE_LOGIN\n  MANUAL_LOGOUT\n  SESSION_EXPIRED\n  ADMIN_REVOKED\n  PASSWORD_CHANGED\n  PHONE_CHANGED\n}\n\nenum ScanType {\n  EMERGENCY\n  CHECK_IN\n  ATTENDANCE\n  OTHER\n}\n\nenum PipelineStepName {\n  CREATE\n  CONFIRM\n  PARTIAL_INVOICE\n  PARTIAL_PAYMENT\n  TOKEN_GENERATION\n  CARD_DESIGN\n  VENDOR_DISPATCH\n  PRINTING_START\n  PRINTING_DONE\n  SHIPMENT_CREATE\n  SHIPMENT_SHIPPED\n  DELIVERY\n  FINAL_INVOICE\n  FINAL_PAYMENT\n  CANCEL\n  REFUND\n}\n\nenum StepStatus {\n  PENDING\n  RUNNING\n  COMPLETED\n  FAILED\n  PARTIAL_FAILED\n  SKIPPED\n}\n\nenum JobStatus {\n  QUEUED\n  RUNNING\n  COMPLETED\n  FAILED\n  RETRYING\n  DEAD\n}\n\nenum PipelineStatus {\n  PENDING\n  IN_PROGRESS\n  COMPLETE\n  FAILED\n}\n\nenum DesignStatus {\n  PENDING\n  IN_PROGRESS\n  COMPLETE\n  FAILED\n}\n\n// NEW enums\nenum SchoolSetupStatus {\n  PENDING_SETUP // registered, no admin has logged in yet\n  ACTIVE // at least one admin has accepted credentials\n  SUSPENDED // temporarily disabled by SuperAdmin\n  TERMINATED // permanently closed\n}\n\nenum AgreementChannel {\n  DASHBOARD // agreed via SuperAdmin dashboard\n  PHYSICAL // physical paper contract\n  EMAIL // email confirmation\n}\n"
}

